import React, { useState } from 'react';

function InicioForm({ onContinue, entrevistadorId }) {
  const [postulante, setPostulante] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (!postulante.trim()) {
      setError('Debes ingresar el nombre del postulante.');
      return;
    }

    try {
      const response = await fetch('http://localhost/sistema-entrevistas/backend/api/crear_postulante.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nombre: postulante.trim() })
      });

      const data = await response.json();
      if (data.status === 'ok') {
        onContinue(data.id); // Solo pasamos el ID del postulante
      } else {
        setError('Error al registrar el postulante.');
      }
    } catch (err) {
      console.error(err);
      setError('No se pudo conectar con el servidor.');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h2>Inicio de entrevista</h2>

      <label>Nombre del postulante:</label>
      <input
        type="text"
        value={postulante}
        onChange={(e) => setPostulante(e.target.value)}
        placeholder="Ej. Juan Pérez"
        required
        style={{ width: '100%', padding: '8px', marginBottom: '15px' }}
      />

      {error && <p style={{ color: 'red' }}>{error}</p>}

      <button
        type="submit"
        style={{
          padding: '10px 20px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer'
        }}
      >
        Comenzar entrevista
      </button>
    </form>
  );
}

export default InicioForm;
